class Solution:
    def simplifiedFractions(self, n: int) -> list:
        from math import gcd
        result = []
        for d in range(2, n + 1):
            for p in range(1, d):
                if gcd(p, d) == 1:
                    result.append(f'{p}/{d}')
        return sorted(result)

