var simplifiedFractions = function(n) {
    function gcd(a, b) { return b === 0 ? a : gcd(b, a % b); }
    const res = [];
    for (let d = 2; d <= n; d++) {
        for (let p = 1; p < d; p++) {
            if (gcd(p, d) === 1) res.push(p + '/' + d);
        }
    }
    return res;
};
